      "first_frame_contract": {
        "location": "东京站新干线清晨站台",
        "visual_center": "美咲与樱子相握的手，旁侧可见美咲丝质礼服肩带与樱子校服裙摆",
        "visible_characters": [
          "佐藤美咲",
          "佐藤樱子"
        ],
        "character_positions": {
          "佐藤美咲": "画面左侧近景，身体微侧向右，正侧脸可见，眼睛向下看相握的手",
          "佐藤樱子": "画面右侧近景，身体微侧向左，正侧脸可见，眼睛向下看相握的手"
        },
        "character_face_visibility": {
          "佐藤美咲": "脸部可见，正侧脸，能看见五官轮廓和向下的眼神",
          "佐藤樱子": "脸部可见，正侧脸，能看见五官轮廓和认真向下的眼神"
        },
        "key_props": [
          "MISAKI_SILK_DRESS_VISUAL",
          "SAKURA_SCHOOL_UNIFORM_VISUAL"
        ],
        "speaking_state": "无人说话，美咲和樱子都闭口沉默，没有远端声音",
        "camera_motion_allowed": "固定机位，允许极轻微稳定推镜"
      },
